/// Executor for UserRegistration flow
pub struct UserRegistrationFlowExecutor<H: UserRegistrationStepHandler> {
    handler: Arc<H>,
}

impl<H: UserRegistrationStepHandler> UserRegistrationFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<UserRegistrationFlowInstance, FlowError> {
        let mut instance = UserRegistrationFlowInstance::new(instance_id);
        instance.status = UserRegistrationFlowStatus::Running;
        instance.current_step = Some(UserRegistrationFlowStep::GenerateVerificationToken);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut UserRegistrationFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            UserRegistrationFlowStep::GenerateVerificationToken => {
                self.handler.handle_generate_verification_token(instance).await?
            }
            UserRegistrationFlowStep::SendVerificationEmail => {
                self.handler.handle_send_verification_email(instance).await?
            }
            UserRegistrationFlowStep::AssignDefaultRole => {
                self.handler.handle_assign_default_role(instance).await?
            }
            UserRegistrationFlowStep::CreateUserSettings => {
                self.handler.handle_create_user_settings(instance).await?
            }
            UserRegistrationFlowStep::CreateProfile => {
                self.handler.handle_create_profile(instance).await?
            }
            UserRegistrationFlowStep::WaitForVerification => {
                self.handler.handle_wait_for_verification(instance).await?
            }
            UserRegistrationFlowStep::ActivateUser => {
                self.handler.handle_activate_user(instance).await?
            }
            UserRegistrationFlowStep::SendWelcomeEmail => {
                self.handler.handle_send_welcome_email(instance).await?
            }
            UserRegistrationFlowStep::LogRegistrationComplete => {
                self.handler.handle_log_registration_complete(instance).await?
            }
            UserRegistrationFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            UserRegistrationFlowStep::SendReminder => {
                self.handler.handle_send_reminder(instance).await?
            }
            UserRegistrationFlowStep::WaitForVerificationRetry => {
                self.handler.handle_wait_for_verification_retry(instance).await?
            }
            UserRegistrationFlowStep::AfterReminderActivation => {
                self.handler.handle_after_reminder_activation(instance).await?
            }
            UserRegistrationFlowStep::ExpireRegistration => {
                self.handler.handle_expire_registration(instance).await?
            }
            UserRegistrationFlowStep::MarkInactive => {
                self.handler.handle_mark_inactive(instance).await?
            }
            UserRegistrationFlowStep::Expired => {
                self.handler.handle_expired(instance).await?;
                None // Terminal step
            }
            UserRegistrationFlowStep::RegistrationFailed => {
                self.handler.handle_registration_failed(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = UserRegistrationFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut UserRegistrationFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != UserRegistrationFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut UserRegistrationFlowInstance) {
        instance.status = UserRegistrationFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut UserRegistrationFlowInstance, error: impl Into<String>) {
        instance.status = UserRegistrationFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = UserRegistrationFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, UserRegistrationFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = UserRegistrationFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = UserRegistrationFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = UserRegistrationFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = UserRegistrationFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
